Let $ABCD$ be the base of the pyramid and let $P$ be the pyramid's apex.

[asy]

import three;

triple A = (0,0,0);

triple B = (1,0,0);

triple C = (1,1,0);

triple D = (0,1,0);

triple P = (0.5,0.5,1);

draw(B--C--D--P--B);

draw(P--C);

draw(B--A--D,dashed);

draw(P--A,dashed);

label("$A$",A,NW);

label("$B$",B,W);

label("$C$",C,S);

label("$D$",D,E);

label("$P$",P,N);

triple F= (0.5,0.5,0);

triple M=(B+C)/2;

